{
  "domain_analysis": {
    "business_context": "Parcel delivery logistics platform handling shipment lifecycle from creation through transit to delivery, with weight-based pricing tiers. Core workflow: create shipment with addresses, transition through states, charge by weight bracket.",
    "bounded_context": "Shipment Management — covers shipment creation, state lifecycle, weight validation, and pricing classification.",
    "ubiquitous_language": [
      { "term": "Shipment", "definition": "A domain entity representing a parcel moving from a pickup address to a delivery address, progressing through a defined state lifecycle." },
      { "term": "Pickup Address", "definition": "The origin location where a parcel is collected. Required at shipment creation." },
      { "term": "Delivery Address", "definition": "The destination location where a parcel must be delivered. Required at shipment creation." },
      { "term": "Shipment State", "definition": "The current lifecycle phase of a shipment. Valid states: Pending, In Transit, Delivered. Transitions are forward-only and irreversible." },
      { "term": "Weight Bracket", "definition": "A pricing classification tier determined by parcel weight: Standard (0–10 kg), Heavy (10–50 kg), Freight (over 50 kg)." },
      { "term": "Standard", "definition": "Weight bracket for shipments weighing more than 0 kg and up to 10 kg inclusive." },
      { "term": "Heavy", "definition": "Weight bracket for shipments weighing more than 10 kg and up to 50 kg inclusive." },
      { "term": "Freight", "definition": "Weight bracket for shipments weighing more than 50 kg, up to the 1000 kg maximum." }
    ]
  },

  "business_rules": [
    {
      "id": "BR-1",
      "rule": "A shipment requires both a pickup address and a delivery address at creation time.",
      "invariant": true,
      "invariant_justification": "A shipment without both endpoints is physically meaningless — there is no valid parcel movement without an origin and destination. This is a data integrity constraint.",
      "testable_assertion": "Any attempt to create a shipment with a null or empty pickup address or delivery address must be rejected."
    },
    {
      "id": "BR-2",
      "rule": "Shipment state transitions are forward-only: Pending → In Transit → Delivered. No backward transitions are permitted.",
      "invariant": true,
      "invariant_justification": "State regression violates physical reality — a parcel that is in transit cannot be un-dispatched. Allowing backward transitions corrupts shipment history and downstream processes (billing, tracking, SLAs).",
      "testable_assertion": "A shipment in state 'In Transit' cannot transition to 'Pending'. A shipment in state 'Delivered' cannot transition to any other state."
    },
    {
      "id": "BR-3",
      "rule": "Delivered is a terminal state. No further state changes are allowed on a delivered shipment.",
      "invariant": true,
      "invariant_justification": "Delivery is a physical finality — the parcel has been handed over. Reopening a delivered shipment corrupts audit trails, billing records, and proof-of-delivery integrity.",
      "testable_assertion": "Any attempt to change the state of a shipment with state 'Delivered' must be rejected."
    },
    {
      "id": "BR-4",
      "rule": "Shipment weight must be strictly greater than 0 kg and must not exceed 1000 kg.",
      "invariant": true,
      "invariant_justification": "Zero or negative weight is physically impossible for a real parcel. The 1000 kg upper bound is a physical/operational constraint (vehicle capacity, handling equipment). Violating this corrupts pricing and operational planning.",
      "testable_assertion": "A shipment with weight <= 0 or weight > 1000 must be rejected at creation."
    },
    {
      "id": "BR-5",
      "rule": "Weight bracket classification: Standard = weight > 0 and <= 10 kg; Heavy = weight > 10 and <= 50 kg; Freight = weight > 50 and <= 1000 kg.",
      "invariant": false,
      "invariant_justification": "The bracket thresholds (10 kg, 50 kg) are business policy decisions that could be adjusted by product/pricing teams without corrupting system integrity. The classification logic itself must exist, but the boundaries are configurable.",
      "testable_assertion": "A 10 kg shipment is classified as Standard. A 10.01 kg shipment is classified as Heavy. A 50 kg shipment is classified as Heavy. A 50.01 kg shipment is classified as Freight."
    },
    {
      "id": "BR-6",
      "rule": "Skipping states is not permitted — a shipment must progress through each state in order (Pending → In Transit → Delivered).",
      "invariant": true,
      "invariant_justification": "Jumping from Pending directly to Delivered skips the physical transit process, corrupting tracking, SLA measurement, and operational audit trails.",
      "testable_assertion": "A shipment in state 'Pending' cannot transition directly to 'Delivered'."
    }
  ],

  "acceptance_criteria": [
    {
      "id": "AC-1",
      "given": "A request to create a shipment with a valid pickup address, delivery address, and weight of 5 kg",
      "when": "The shipment is created",
      "then": "The shipment is persisted in state 'Pending' with weight bracket 'Standard'"
    },
    {
      "id": "AC-2",
      "given": "A request to create a shipment with a missing delivery address",
      "when": "The creation is attempted",
      "then": "The system rejects the request with a validation error indicating the delivery address is required"
    },
    {
      "id": "AC-3",
      "given": "A request to create a shipment with a missing pickup address",
      "when": "The creation is attempted",
      "then": "The system rejects the request with a validation error indicating the pickup address is required"
    },
    {
      "id": "AC-4",
      "given": "A shipment in state 'Pending'",
      "when": "A transition to 'In Transit' is requested",
      "then": "The shipment state changes to 'In Transit'"
    },
    {
      "id": "AC-5",
      "given": "A shipment in state 'In Transit'",
      "when": "A transition back to 'Pending' is requested",
      "then": "The system rejects the transition and the shipment remains 'In Transit'"
    },
    {
      "id": "AC-6",
      "given": "A shipment in state 'In Transit'",
      "when": "A transition to 'Delivered' is requested",
      "then": "The shipment state changes to 'Delivered' and no further state transitions are accepted"
    },
    {
      "id": "AC-7",
      "given": "A shipment in state 'Delivered'",
      "when": "Any state transition is requested",
      "then": "The system rejects the transition; the shipment remains 'Delivered'"
    },
    {
      "id": "AC-8",
      "given": "A request to create a shipment with weight 0 kg",
      "when": "The creation is attempted",
      "then": "The system rejects the request with a validation error indicating weight must be positive"
    },
    {
      "id": "AC-9",
      "given": "A request to create a shipment with weight 1001 kg",
      "when": "The creation is attempted",
      "then": "The system rejects the request with a validation error indicating weight exceeds the 1000 kg maximum"
    },
    {
      "id": "AC-10",
      "given": "A shipment is created with weight 10 kg",
      "when": "The weight bracket is calculated",
      "then": "The shipment is classified as 'Standard'"
    },
    {
      "id": "AC-11",
      "given": "A shipment is created with weight 25 kg",
      "when": "The weight bracket is calculated",
      "then": "The shipment is classified as 'Heavy'"
    },
    {
      "id": "AC-12",
      "given": "A shipment is created with weight 75 kg",
      "when": "The weight bracket is calculated",
      "then": "The shipment is classified as 'Freight'"
    },
    {
      "id": "AC-13",
      "given": "A shipment in state 'Pending'",
      "when": "A transition directly to 'Delivered' is requested",
      "then": "The system rejects the transition; the shipment must pass through 'In Transit' first"
    }
  ],

  "edge_cases": [
    { "scenario": "Shipment created with weight exactly 10 kg", "expected_behavior": "Classified as 'Standard' — the boundary is inclusive on the upper end of the Standard bracket." },
    { "scenario": "Shipment created with weight exactly 50 kg", "expected_behavior": "Classified as 'Heavy' — the boundary is inclusive on the upper end of the Heavy bracket." },
    { "scenario": "Shipment created with weight exactly 1000 kg", "expected_behavior": "Accepted and classified as 'Freight' — 1000 kg is the upper limit, not exceeded." },
    { "scenario": "Shipment created with weight of 0.001 kg (fractional, near-zero)", "expected_behavior": "Accepted — weight is positive. Classified as 'Standard'. System should support decimal precision." },
    { "scenario": "Shipment created with negative weight (-5 kg)", "expected_behavior": "Rejected — weight must be strictly positive." },
    { "scenario": "Concurrent state transitions on the same shipment (race condition)", "expected_behavior": "Only one transition succeeds; the second is rejected based on the already-updated state. Optimistic locking or equivalent concurrency control is expected." },
    { "scenario": "Attempt to modify pickup or delivery address after shipment is In Transit or Delivered", "expected_behavior": "Spec does not address this — treat as an open question. Recommend immutability of addresses after creation to preserve audit integrity." },
    { "scenario": "Shipment weight provided with excessive decimal precision (e.g., 10.000000001 kg)", "expected_behavior": "System should define a rounding/precision policy. At bracket boundaries, precision determines classification." }
  ],

  "business_impact": {
    "financial": "Weight bracket classification directly drives pricing. Incorrect classification means revenue leakage (undercharging heavy parcels) or customer disputes (overcharging light parcels). Boundary precision at 10 kg and 50 kg thresholds is a direct billing concern.",
    "operational": "State lifecycle integrity ensures reliable tracking, dispatch coordination, and SLA measurement. If backward transitions are allowed, operational dashboards, driver assignments, and warehouse workflows become unreliable.",
    "user": "Customers depend on accurate shipment status for planning. A shipment that regresses from 'In Transit' to 'Pending' erodes trust. Clear rejection messages on invalid inputs improve self-service experience.",
    "risk": "Primary risks: (1) pricing disputes from ambiguous bracket boundaries, (2) audit trail corruption from state regression, (3) data integrity issues from missing address validation. All are mitigated by strict enforcement of the stated rules.",
    "stakeholders_affected": [
      { "group": "Shippers (customers)", "impact": "Depend on correct pricing by weight and accurate shipment status visibility." },
      { "group": "Recipients", "impact": "Rely on delivery status accuracy for availability planning." },
      { "group": "Operations / Dispatch", "impact": "Use shipment state to coordinate pickups, routing, and last-mile delivery." },
      { "group": "Finance / Billing", "impact": "Weight bracket classification feeds directly into invoicing. Errors create billing disputes." },
      { "group": "Customer Support", "impact": "Handle escalations when status or pricing is incorrect. Clear rules reduce support volume." }
    ]
  },

  "confidence": {
    "level": 72,
    "reasoning": "The spec is clear on core lifecycle and weight rules, but leaves several domain questions unanswered: boundary inclusivity at bracket thresholds is ambiguous (the spec says '0-10', '10-50', 'over 50' — the 10 and 50 boundaries overlap), weight precision is unspecified, address immutability post-creation is not addressed, and there is no mention of cancellation or exception flows. The rules that ARE stated are unambiguous and well-structured.",
    "high_confidence_areas": [
      "State lifecycle: Pending → In Transit → Delivered with no backward transitions",
      "Delivered is terminal",
      "Both addresses required at creation",
      "Weight must be positive and <= 1000 kg",
      "Three weight brackets exist with defined thresholds"
    ],
    "low_confidence_areas": [
      "Exact boundary inclusivity for weight brackets (is 10 kg Standard or Heavy?)",
      "Whether weight can be modified after creation",
      "Whether addresses can be modified after creation",
      "Cancellation flow — can a Pending shipment be cancelled?",
      "Decimal precision policy for weight",
      "Whether the initial state is always Pending or can be specified"
    ],
    "assumptions": [
      "Weight bracket boundaries are upper-inclusive: Standard includes 10 kg, Heavy includes 50 kg, Freight includes 1000 kg",
      "Shipments always start in Pending state",
      "Weight is set at creation and immutable thereafter",
      "Pending → In Transit → Delivered is the only valid forward path (no skip allowed)",
      "No cancellation state exists in the current model"
    ]
  },

  "escalations": [
    {
      "type": "ambiguity",
      "description": "Weight bracket boundary overlap: the spec says '0-10 kg is standard, 10-50 kg is heavy'. A shipment weighing exactly 10 kg matches both brackets. The spec does not clarify whether 10 kg belongs to Standard or Heavy, and similarly for 50 kg.",
      "affected_stakeholders": ["Finance / Billing", "Shippers (customers)"],
      "options": [
        "A: Upper-inclusive — 10 kg is Standard, 50 kg is Heavy (bracket boundary belongs to the lower tier)",
        "B: Lower-inclusive — 10 kg is Heavy, 50 kg is Freight (bracket boundary belongs to the upper tier)"
      ],
      "recommendation": "Option A (upper-inclusive) is the industry convention and more customer-friendly — charges the lower rate at the boundary. Recommend confirming with product manager."
    },
    {
      "type": "missing_context",
      "description": "No cancellation or exception flow defined. Can a shipment in Pending state be cancelled? What happens if a shipment is lost or returned in transit? Real logistics operations always need exception handling paths.",
      "affected_stakeholders": ["Shippers (customers)", "Operations / Dispatch", "Customer Support"],
      "options": [
        "A: Add a 'Cancelled' terminal state reachable only from 'Pending'",
        "B: Add 'Cancelled' reachable from both 'Pending' and 'In Transit'",
        "C: Defer — ship without cancellation for MVP"
      ],
      "recommendation": "Option B reflects logistics reality (parcels can be recalled in transit), but Option A is simpler for MVP. Escalate to product manager for priority guidance."
    },
    {
      "type": "missing_context",
      "description": "Weight precision and mutability are unspecified. Can weight be updated after creation (e.g., after physical weighing at warehouse)? What decimal precision is supported? At bracket boundaries, rounding policy directly affects pricing.",
      "affected_stakeholders": ["Finance / Billing", "Operations / Dispatch"],
      "options": [
        "A: Weight is immutable after creation, precision to 2 decimal places",
        "B: Weight can be corrected until shipment is In Transit, precision to 3 decimal places"
      ],
      "recommendation": "Option B aligns with logistics reality — estimated weight at booking is often corrected after physical measurement. Recommend confirming with operations team."
    }
  ],

  "rejection_reasons": []
}

